import React, { useEffect, useRef } from 'react';
import PropTypes from 'prop-types';
import { useTheme } from '../../contexts/ThemeContext';
import tsParticles from 'tsparticles';
import styles from './ParticleBackground.module.css';

/**
 * Particle Background Component
 * 
 * Creates an interactive particle background using tsparticles.
 * Implementation for task T042.
 */
const ParticleBackground = ({ 
  id = 'tsparticles', 
  className = '', 
  customConfig = null,
  ...props 
}) => {
  const { theme } = useTheme();
  const containerRef = useRef(null);
  const initialized = useRef(false);

  // Default configurations based on theme
  const defaultConfigs = {
    light: {
      background: {
        color: {
          value: '#ffffff',
        },
      },
      fpsLimit: 60,
      particles: {
        color: {
          value: '#3b82f6',
        },
        links: {
          color: '#3b82f6',
          distance: 150,
          enable: true,
          opacity: 0.5,
          width: 1,
        },
        collisions: {
          enable: true,
        },
        move: {
          direction: 'none',
          enable: true,
          outMode: 'bounce',
          random: false,
          speed: 2,
          straight: false,
        },
        number: {
          density: {
            enable: true,
            value_area: 800,
          },
          value: 80,
        },
        opacity: {
          value: 0.5,
        },
        shape: {
          type: 'circle',
        },
        size: {
          random: true,
          value: 5,
        },
      },
      detectRetina: true,
      interactivity: {
        detectOn: 'canvas',
        events: {
          onClick: {
            enable: true,
            mode: 'push',
          },
          onHover: {
            enable: true,
            mode: 'repulse',
          },
          resize: true,
        },
        modes: {
          bubble: {
            distance: 400,
            duration: 2,
            opacity: 0.8,
            size: 40,
          },
          push: {
            quantity: 4,
          },
          repulse: {
            distance: 100,
            duration: 0.4,
          },
        },
      },
    },
    dark: {
      background: {
        color: {
          value: '#0f172a',
        },
      },
      fpsLimit: 60,
      particles: {
        color: {
          value: '#38bdf8',
        },
        links: {
          color: '#38bdf8',
          distance: 150,
          enable: true,
          opacity: 0.5,
          width: 1,
        },
        collisions: {
          enable: true,
        },
        move: {
          direction: 'none',
          enable: true,
          outMode: 'bounce',
          random: false,
          speed: 2,
          straight: false,
        },
        number: {
          density: {
            enable: true,
            value_area: 800,
          },
          value: 80,
        },
        opacity: {
          value: 0.5,
        },
        shape: {
          type: 'circle',
        },
        size: {
          random: true,
          value: 5,
        },
      },
      detectRetina: true,
      interactivity: {
        detectOn: 'canvas',
        events: {
          onClick: {
            enable: true,
            mode: 'push',
          },
          onHover: {
            enable: true,
            mode: 'repulse',
          },
          resize: true,
        },
        modes: {
          bubble: {
            distance: 400,
            duration: 2,
            opacity: 0.8,
            size: 40,
          },
          push: {
            quantity: 4,
          },
          repulse: {
            distance: 100,
            duration: 0.4,
          },
        },
      },
    },
  };

  useEffect(() => {
    // Don't proceed if already initialized
    if (initialized.current) return;

    // Initialize particles if tsParticles is available
    if (tsParticles && containerRef.current) {
      const config = customConfig || defaultConfigs[theme];
      
      // Load the particles
      tsParticles.load(id, config)
        .then((container) => {
          initialized.current = true;
        })
        .catch((error) => {
          console.error('Error initializing particles:', error);
        });
    }

    // Cleanup function
    return () => {
      if (initialized.current) {
        // Destroy particles instance on unmount
        const instance = tsParticles.domItem(id);
        if (instance) {
          instance.destroy();
          initialized.current = false;
        }
      }
    };
  }, [id, customConfig, theme]);

  // Update particles when theme changes
  useEffect(() => {
    if (initialized.current) {
      const instance = tsParticles.domItem(id);
      if (instance) {
        // Destroy the existing instance
        instance.destroy();
        initialized.current = false;
        
        // Create a new one with updated theme
        const config = customConfig || defaultConfigs[theme];
        tsParticles.load(id, config)
          .then((container) => {
            initialized.current = true;
          })
          .catch((error) => {
            console.error('Error reinitializing particles:', error);
          });
      }
    }
  }, [theme, id, customConfig]);

  return (
    <div 
      id={id}
      ref={containerRef}
      className={`${styles['particles-container']} ${className}`}
      data-testid="particle-background"
      {...props}
    />
  );
};

ParticleBackground.propTypes = {
  id: PropTypes.string,
  className: PropTypes.string,
  customConfig: PropTypes.object,
};

export default ParticleBackground;
